content:
今日份的作业是电影级的Cosplay海报，至于是什么电影你别管，成图都是我审过的，不健康的都没发出来。

 这个提示词是直接从Nnao Banana那里照搬过来的，相比之下，GPT-Image-2的审美还是要更好一些，人物的高P感是故意用提示词强化的，就是为了区别于真实系，表现得更加浮夸和明媚。

 提示词：

 {
   "subject": {
     "描述": "以[xxx]为主体的电影级Cosplay海报，动态姿态；保留原始面部特征并转化为真实人类质感；呈现写真出道氛围，带有亲密日式美感"
   },
   "style": {
     "风格": "高端杂志封面风",
     "特征": [
       "排版密度高（字体+材质叠加）",
       "商业摄影质感",
       "信息素氛围（感性吸引力）",
       "高光泽",
       "高对比度"
     ]
   },
   "model": {
     "身材": "8.5头身超模比例，S曲线",
     "皮肤": "瓷白肌肤，真实质感（次表面散射、毛孔、细绒毛、油润光泽）",
     "特征": [
       "丰满胸型",
       "精致锁骨与颈线",
       "强烈女性吸引力"
     ]
   },
   "face": {
     "基础": "日系缪斯脸型",
     "特征": "叠加[xxx]标志性面部特征",
     "细节": [
       "柔焦眼神",
       "水润玻璃唇",
       "肌肤通透感",
       "眼部高光"
     ]
   },
   "pose": {
     "姿态": [
       "开放且具有吸引力的身体语言",
       "带有邀请感的眼神",
       "手部动作丰富自然"
     ]
   },
   "hair": {
     "描述": "[xxx]标志性发型（真实沙龙级呈现，无假发）",
     "特征": [
       "符合重力与重量感",
       "自然碎发",
       "结构化定型（轻微反重力效果）",
       "背光增强体积感"
     ]
   },
   "costume": {
     "描述": "高度还原[xxx]原作服装",
     "特征": [
       "高级定制级材质转译",
       "真实奢华面料",
       "保留原始设计",
       "通过服装与身体结合体现魅力",
       "裸露区域带有细腻肌肤光泽"
     ]
   },
   "environment": {
     "场景": "符合[xxx]设定的环境",
     "风格": [
       "高预算电影布景",
       "结构有序但信息丰富",
       "轻微雾气",
       "散景效果（bokeh）"
     ]
   },
   "composition": {
     "构图": [
       "竖版海报（2:3）",
       "近景到中景",
       "浅景深",
       "文字作为构图框架",
       "人物部分覆盖文字层"
     ]
   },
   "lighting": {
     "灯光": [
       "电影级商业布光",
       "冷色环境光（青色）+暖色主光（肤色）",
       "头发轮廓光",
       "高对比用于印刷质感"
     ]
   },
   "typography": {
     "排版逻辑": "基于[xxx]世界观推导",
     "层级": [
       {
         "层级": 1,
         "内容": "日语主标题（带张力与暗示感）",
         "字体": "高对比纤细衬线体，可斜体"
       },
       {
         "层级": 2,
         "内容": "[xxx]罗马音名称",
         "字体": "中等字重衬线体"
       },
       {
         "层级": 3,
         "内容": "英文短叙述/标语",
         "字体": "细衬线体"
       },
       {
         "层级": 4,
         "内容": "圆形印章/徽章（基于设定）"
       },
       {
         "层级": 5,
         "内容": "Jerlin + 期号",
         "字体": "极细Didot，宽字距，角落布局"
       },
       {
         "层级": 6,
         "内容": "条形码 + 价格标签"
       }
     ],
     "混排": "日语 + 平假名 + 罗马字，字重递减",
     "系统": "基于网格系统的封面设计"
   },
   "mood": {
     "氛围": [
       "梦幻",
       "微性感",
       "亲密感（恋人视角）",
       "欲望张力"
     ]
   },
   "negative": {
     "避免": [
       "文字重复",
       "文字阴影",
       "发光效果",
       "描边"
     ]
   },
   "aspect_ratio": "2:3"
 }
